const found = $input.all();
const original = $('Code Parse').first().json;

const normalize = (s) =>
  String(s || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '');

const wanted = normalize(original.task_name);

let matched = found.find(item =>
  normalize(item.json.task_name) === wanted
);

if (!matched) {
  matched = found.find(item =>
    normalize(item.json.task_name).includes(wanted) ||
    wanted.includes(normalize(item.json.task_name))
  );
}

if (!matched || matched.json.row_number == null) {
  return [{
    json: {
      user_id: original.user_id,
      replyToken: original.replyToken,
      reply_message: `❌ ไม่พบงาน "${original.task_name}" ในรายการงานค้าง`,
      row_number: null,
      skip_update: true
    }
  }];
}

return [{
  json: {
    user_id: original.user_id,
    replyToken: original.replyToken,
    task_name: matched.json.task_name,
    reply_message: `✅ อัปเดตสถานะงาน "${matched.json.task_name}" เป็น done แล้วครับ!`,
    row_number: matched.json.row_number,
    skip_update: false
  }
}];

const rows = $input.all();
const original = $('Code Parse').first().json;

let message = '';

const padTime = (raw) => {
  const s = String(raw || '').trim();
  if (!s) return '07:00';
  const parts = s.split(':');
  if (parts.length !== 2) return '07:00';

  const h = Number(parts[0]);
  const m = Number(parts[1]);
  if (Number.isNaN(h) || Number.isNaN(m)) return '07:00';

  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
};

const nowBkk = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Bangkok',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(new Date());

const viewMode = String(original.view_mode || 'pending_all');

let filteredRows = rows.filter(r => {
  const status = String(r.json.status || '').toLowerCase();
  if (viewMode === 'done_all') return status === 'done';
  return status === 'pending';
});

if (viewMode === 'pending_today') {
  filteredRows = filteredRows.filter(r =>
    String(r.json.deadline_date || '') === nowBkk
  );
}

if (filteredRows.length === 0) {
  message =
    viewMode === 'done_all'
      ? '✅ ยังไม่มีงานที่เสร็จแล้วครับ'
      : viewMode === 'pending_today'
        ? '✅ วันนี้ไม่มีงานค้างครับ 🎉'
        : '✅ ตอนนี้ไม่มีงานค้างเลยครับ ทำครบหมดแล้ว! 🎉';
} else {
  const tasks = filteredRows
    .map(r => r.json)
    .map(t => {
      const timeStr = padTime(t.deadline_time);
      t._deadline = new Date(`${t.deadline_date}T${timeStr}:00+07:00`);
      return t;
    })
    .filter(t => !isNaN(t._deadline));

  const sorted = tasks.sort((a, b) => a._deadline - b._deadline);

  if (sorted.length === 0) {
    message = '⚠️ พบข้อมูลงานในชีต แต่รูปแบบวันเวลาบางรายการไม่ถูกต้องครับ';
  } else {
    const now = new Date();

    message =
      viewMode === 'done_all'
        ? `✅ งานที่เสร็จแล้ว (${sorted.length} งาน)\n`
        : viewMode === 'pending_today'
          ? `📋 งานค้างวันนี้ (${sorted.length} งาน)\n`
          : `📋 งานค้างทั้งหมด (${sorted.length} งาน)\n`;

    message += `─────────────────\n`;

    sorted.forEach((task, i) => {
      const dl = task._deadline;
      const overdue = viewMode !== 'done_all' && dl < now;

      const dlStr = dl.toLocaleDateString('th-TH', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        timeZone: 'Asia/Bangkok'
      });

      const icon =
        viewMode === 'done_all'
          ? '✅'
          : overdue
            ? '🔴'
            : '📌';

      message += `${i + 1}. ${icon} ${task.task_name}\n`;
      message += `   📅 ${dlStr}\n`;
      message += `   📚 ${task.subject || '-'}\n\n`;
    });

    message += `─────────────────\n`;
    message +=
      viewMode === 'done_all'
        ? 'พิมพ์ "มีงานอะไรบ้าง" เพื่อดูงานค้างทั้งหมดได้ครับ 📋'
        : 'พิมพ์ "ทำ [ชื่องาน] เสร็จแล้ว" เพื่ออัปเดตนะครับ ✏️';
  }
}

return [{
  json: {
    user_id: original.user_id,
    replyToken: original.replyToken,
    reply_message: message
  }
}];

const original = $input.first().json;
const base = $('Code Parse').first().json;

return [{
  json: {
    user_id: original.user_id || base.user_id || '',
    replyToken: original.replyToken || base.replyToken || '',
    reply_message:
      base.reply_message ||
      original.reply_message ||
      '❓ ขอโทษครับ ไม่เข้าใจคำสั่งนี้\n\nลองพิมพ์แบบนี้นะครับ:\n• "มีประชุม 10 โมงพรุ่งนี้"\n• "กำหนดส่ง Report CSI403 วันที่ 20"\n• "ทำ Assignment CSI401 เสร็จแล้ว"\n• "มีงานอะไรบ้าง"'
  }
}];

const item = $input.first().json;
const base = $('Code Parse').first().json;

const replyMsg   = item.reply_message || base.reply_message || 'ดำเนินการเรียบร้อยครับ ✅';
const replyToken = item.replyToken    || base.replyToken    || '';

return [{ json: { replyToken, reply_message: replyMsg } }];

const editFields = $('Edit Fields1').first().json;
const sessionRows = $input.all();

// session ล่าสุดของ user
const sessionCandidates = sessionRows
  .filter(r => String(r.json.user_id || '') === String(editFields.userId || ''))
  .filter(r => String(r.json.status || '').toLowerCase() === 'session')
  .map(r => r.json)
  .sort((a, b) => {
    const aRow = Number(a.row_number || 0);
    const bRow = Number(b.row_number || 0);
    if (aRow !== bRow) return bRow - aRow;

    const aTime = new Date(a.created_at || 0).getTime();
    const bTime = new Date(b.created_at || 0).getTime();
    return bTime - aTime;
  });

const sessionRow = sessionCandidates[0] || null;
const session = sessionRow || {};

const hasActiveSession = !!(
  sessionRow &&
  (
    String(session.task_name || '').trim() !== '' ||
    String(session.deadline_date || '').trim() !== '' ||
    String(session.deadline_time || '').trim() !== '' ||
    String(session.subject || '').trim() !== ''
  )
);

// task ล่าสุดจริงของ user (ไม่เอา session)
const realRows = sessionRows
  .map(r => r.json)
  .filter(r =>
    String(r.user_id || '') === String(editFields.userId || '') &&
    String(r.status || '').toLowerCase() !== 'session'
  )
  .sort((a, b) => {
    const aRow = Number(a.row_number || 0);
    const bRow = Number(b.row_number || 0);
    if (aRow !== bRow) return bRow - aRow;

    const aTime = new Date(a.created_at || 0).getTime();
    const bTime = new Date(b.created_at || 0).getTime();
    return bTime - aTime;
  });

const latestTask = realRows[0] || {};

return [{
  json: {
    userId: editFields.userId,
    replyToken: editFields.replyToken,
    text: editFields.text,

    session_task_name: session.task_name || '',
    session_subject: session.subject || '',
    session_task_type: session.task_type || '',
    session_deadline_date: session.deadline_date || '',
    session_deadline_time: session.deadline_time || '',
    session_has_time: session.has_time || '',
    has_pending_session: hasActiveSession ? 'true' : 'false',

    latest_task_name: latestTask.task_name || '',
    latest_subject: latestTask.subject || '',
    latest_task_type: latestTask.task_type || '',
    latest_deadline_date: latestTask.deadline_date || '',
    latest_deadline_time: latestTask.deadline_time || '',
    latest_status: latestTask.status || '',

    last_task_name: latestTask.task_name || ''
  }
}];

const rows = $input.all();
const parsed = $('Code Parse').first().json;

const newDate = parsed.deadline_date || '';
const newTime = parsed.deadline_time || '';
const newTaskType = parsed.task_type || '';

// Only check time conflict for Meeting tasks that have a time
const shouldCheckTime = newTaskType === 'Meeting' && newTime !== '';

let conflicts = [];

if (shouldCheckTime) {
  const [newH, newM] = newTime.split(':').map(Number);
  const newMins = newH * 60 + newM;

  for (const row of rows) {
    const t = row.json;
    if (!t.deadline_time || t.deadline_time === '') continue;
    if (t.task_name === parsed.task_name) continue; // skip same task

    const [h, m] = String(t.deadline_time).split(':').map(Number);
    const existMins = h * 60 + m;
    const diff = Math.abs(newMins - existMins);

    if (diff < 60) { // within 60 minutes = conflict
      conflicts.push({
        task_name: t.task_name,
        deadline_time: t.deadline_time,
        subject: t.subject || '-'
      });
    }
  }
}

const hasConflict = conflicts.length > 0;

if (hasConflict) {
  const conflictList = conflicts.map(c =>
    `• ${c.task_name} (${c.subject}) เวลา ${c.deadline_time}`
  ).join('\n');

  const warningMsg =
    `⚠️ พบนัดซ้อนในวันที่ ${newDate}!\n\n` +
    `งานที่ทับกัน:\n${conflictList}\n\n` +
    `ต้องการบันทึก "${parsed.task_name}" เวลา ${newTime} ต่อไหมครับ?`;

  return [{
    json: {
      has_conflict: "true",
      user_id:      parsed.user_id,
      replyToken:   parsed.replyToken,
      reply_message: warningMsg,
      quick_reply_type: 'conflict_confirm',
      // Pass through all task data so we can save later
      pending_task: JSON.stringify({
        user_id:       parsed.user_id,
        task_name:     parsed.task_name,
        subject:       parsed.subject,
        task_type:     parsed.task_type,
        deadline_date: parsed.deadline_date,
        deadline_time: parsed.deadline_time,
        has_time:      parsed.has_time,
        created_at:    parsed.created_at
      })
    }
  }];
}

// No conflict — pass through for normal save
return [{
  json: {
    has_conflict: "false",
    ...parsed
  }
}];

const found = $input.all();
const original = $('Code Parse').first().json;

if (found.length === 0 || found[0].json.row_number == null) {
  return [{
    json: {
      user_id:      original.user_id,
      replyToken:   original.replyToken,
