    replyToken:   original.replyToken,
    task_name:    task.task_name,
    reply_message: `🗑️ ลบงาน "${task.task_name}" เรียบร้อยแล้วครับ!`,
    row_number:   task.row_number,
    skip_delete:  false
  }
