const found = $input.all();
const original = $('Code Parse').first().json;

const normalize = (s) =>
  String(s || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '');

const wanted = normalize(original.task_name);

let matched = found.find(item =>
  normalize(item.json.task_name) === wanted
);

if (!matched) {
  matched = found.find(item =>
    normalize(item.json.task_name).includes(wanted) ||
    wanted.includes(normalize(item.json.task_name))
  );
}

if (!matched || matched.json.row_number == null) {
  return [{
    json: {
      user_id: original.user_id,
      replyToken: original.replyToken,
      row_number: null,
      task_id: '',
      skip_update: true,
      reply_message: `❌ ไม่พบงาน "${original.task_name}" ที่ต้องการแก้ไข`
    }
  }];
}

const oldTask = matched.json;

const finalTaskName = original.new_task_name && String(original.new_task_name).trim() !== ''
  ? original.new_task_name
  : oldTask.task_name;

const finalDeadlineDate = original.deadline_date && String(original.deadline_date).trim() !== ''
  ? original.deadline_date
  : oldTask.deadline_date;

const finalDeadlineTime = original.deadline_time && String(original.deadline_time).trim() !== ''
  ? original.deadline_time
  : oldTask.deadline_time;

const finalStatus = original.new_status && String(original.new_status).trim() !== ''
  ? original.new_status
  : oldTask.status;

const hasTime = finalDeadlineTime && String(finalDeadlineTime).trim() !== '' ? 'true' : 'false';

return [{
  json: {
    user_id: original.user_id,
    replyToken: original.replyToken,
    row_number: oldTask.row_number,
    task_id: oldTask.task_id,
    task_name: oldTask.task_name,
    new_task_name: finalTaskName,
    deadline_date: finalDeadlineDate,
    deadline_time: finalDeadlineTime,
    has_time: hasTime,
    new_status: finalStatus,
    notified_1h: oldTask.notified_1h || 'false',
    notified_15m: oldTask.notified_15m || 'false',
    skip_update: false,
    reply_message:
      `✅ แก้ไขงานเรียบร้อยแล้ว\n\n` +
      `📌 ${finalTaskName}\n` +
      `📅 ${finalDeadlineDate || '-'} ${finalDeadlineTime || ''}\n` +
      `📍 สถานะ: ${finalStatus}`
  }
}];

const items = $input.all();
const now = new Date();

const userMap = {};
for (const item of items) {
  const task = item.json;
  // กรองเฉพาะ pending (ไม่เอา done, session)
  if (!task.user_id || !task.deadline_date) continue;
  if (String(task.status).toLowerCase() !== 'pending') continue;

  const padTime = (raw) => {
    const s = String(raw || '').trim();
    if (!s) return '07:00';
    const parts = s.split(':');
    if (parts.length !== 2) return '07:00';
    const h = Number(parts[0]);
    const m = Number(parts[1]);
    if (Number.isNaN(h) || Number.isNaN(m)) return '07:00';
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
  };
  const timeStr = padTime(task.deadline_time);
  task._deadline = new Date(`${task.deadline_date}T${timeStr}:00+07:00`);
  if (isNaN(task._deadline)) continue;

  if (!userMap[task.user_id]) userMap[task.user_id] = [];
  userMap[task.user_id].push(task);
}

const results = [];
for (const [userId, tasks] of Object.entries(userMap)) {
  const sorted = tasks.sort((a, b) => a._deadline - b._deadline);

  const overdue  = sorted.filter(t => t._deadline < now);
  const upcoming = sorted.filter(t => {
    const daysLeft = (t._deadline - now) / 86400000;
    return daysLeft >= 0 && daysLeft <= 7;
  });
  const allPending = sorted.filter(t => t._deadline >= now);

  let message = `🌅 อรุณสวัสดิ์ครับ! สรุปงานประจำวัน\n`;
  message += `📅 ${now.toLocaleDateString('th-TH', {
    weekday:'long', year:'numeric', month:'long', day:'numeric',
    timeZone:'Asia/Bangkok'
  })}\n`;
  message += `─────────────────\n`;

  if (overdue.length > 0) {
    message += `\n🔴 เลยกำหนดแล้ว! (${overdue.length} งาน)\n`;
    overdue.forEach(task => {
      const dl = task._deadline;
      const dlStr = dl.toLocaleDateString('th-TH', {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'});
      message += `❗ ${task.task_name} (${task.subject || '-'}) — ${dlStr}\n`;
    });
  }

  if (upcoming.length > 0) {
    message += `\n⚡ งาน deadline ใน 7 วัน (${upcoming.length} งาน)\n`;
    upcoming.forEach(task => {
      const dl = task._deadline;
      const daysLeft  = Math.round((dl - now) / 86400000);
      const hoursLeft = Math.round((dl - now) / 3600000);
      const dlStr = dl.toLocaleDateString('th-TH', {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit', timeZone:'Asia/Bangkok'});
      const urgency = hoursLeft < 3 ? '🔴' : hoursLeft < 6 ? '🟠' : daysLeft <= 1 ? '🟡' : '🟢';
      message += `${urgency} ${task.task_name} (${task.subject || '-'}) — ${dlStr}\n`;
    });
  } else if (overdue.length === 0) {
    message += `\n✅ ไม่มีงาน deadline ใน 7 วันข้างหน้า\n`;
  }

  message += `\n─────────────────`;
  message += `\n📊 งานค้างรวม: ${allPending.length} งาน`;
  message += `\nสู้ๆ นะครับ! 💪`;

  results.push({ json: { user_id: userId, push_message: message } });
}

if (results.length === 0) return [];
return results;

const updated = $('GSheet Auto Done Overdue1').first().json;
const original = $('Switch Deadline Action1').first().json;

return [{
  json: {
    ...original,
    ...updated
  }
}];

const items = $input.all();
const results = [];

const nowParts = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'Asia/Bangkok',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  hourCycle: 'h23',
}).formatToParts(new Date());

const getPart = (type) => nowParts.find(p => p.type === type)?.value || '';

const nowY = Number(getPart('year'));
const nowM = Number(getPart('month'));
const nowD = Number(getPart('day'));
const nowH = Number(getPart('hour'));
const nowMin = Number(getPart('minute'));

const nowUtcMs = Date.UTC(nowY, nowM - 1, nowD, nowH, nowMin);

const padTime = (raw) => {
  const s = String(raw || '').trim();
  if (!s) return '07:00';
  const parts = s.split(':');
  if (parts.length !== 2) return '07:00';
  const h = Number(parts[0]);
  const m = Number(parts[1]);
  if (Number.isNaN(h) || Number.isNaN(m)) return '07:00';
  return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
};

for (const item of items) {
  const task = item.json;

  if (!task.task_id) continue;
  if (!task.user_id) continue;
  if (!task.deadline_date) continue;
  if (String(task.status).toLowerCase() !== 'pending') continue;

  const dateStr = String(task.deadline_date).trim();
  const dateParts = dateStr.split('-');
  if (dateParts.length !== 3) continue;

  const year = Number(dateParts[0]);
  const month = Number(dateParts[1]);
  const day = Number(dateParts[2]);

  const rawTime = padTime(task.deadline_time);
  const [hour, minute] = rawTime.split(':').map(Number);

  if (
    Number.isNaN(year) ||
    Number.isNaN(month) ||
    Number.isNaN(day) ||
    Number.isNaN(hour) ||
    Number.isNaN(minute)
  ) continue;

  const deadlineUtcMs = Date.UTC(year, month - 1, day, hour, minute);
  const minsLeft = Math.round((deadlineUtcMs - nowUtcMs) / 60000);
  const minsOverdue = Math.abs(minsLeft);

  const notified1h = String(task.notified_1h).toLowerCase() === 'true';
  const notified15m = String(task.notified_15m).toLowerCase() === 'true';

  let action = '';
  let notifyKey = '';
  let pushMessage = '';

  const hh = String(hour).padStart(2, '0');
  const mm = String(minute).padStart(2, '0');

  if (minsLeft > 0) {
    if (minsLeft <= 15 && !notified15m) {
      action = 'notify_15m';
      notifyKey = 'notified_15m';
      pushMessage =
        `⏰ อีก 15 นาทีจะถึงกำหนดแล้ว\n\n` +
        `📌 ${task.task_name || '-'}\n` +
        `📚 ${task.subject || '-'}\n` +
        `🗂️ ${task.task_type || '-'}\n` +
        `📅 กำหนด: ${dateStr} ${hh}:${mm}`;
    } else if (minsLeft <= 60 && !notified1h) {
      action = 'notify_1h';
      notifyKey = 'notified_1h';
      pushMessage =
        `🔔 อีก 1 ชั่วโมงจะถึงกำหนดแล้ว\n\n` +
        `📌 ${task.task_name || '-'}\n` +
        `📚 ${task.subject || '-'}\n` +
        `🗂️ ${task.task_type || '-'}\n` +
        `📅 กำหนด: ${dateStr} ${hh}:${mm}`;
    }
  } else {
    if (minsOverdue >= 60) {
      action = 'auto_done_1h_overdue';
      pushMessage =
        `✅ ระบบปิดงานอัตโนมัติแล้ว\n\n` +
        `📌 ${task.task_name || '-'}\n` +
        `📚 ${task.subject || '-'}\n` +
        `🗂️ ${task.task_type || '-'}\n` +
        `📅 เลยกำหนดมาแล้ว 1 ชั่วโมง (${dateStr} ${hh}:${mm})\n\n` +
        `หากยังไม่เสร็จ สามารถแก้สถานะกลับเป็น pending ได้ครับ`;
    }
  }

  if (!action) continue;

  results.push({
    json: {
      task_id: task.task_id,
      user_id: task.user_id,
      row_number: task.row_number,
      action,
      notify_key: notifyKey,
      push_message: pushMessage,
      current_notified_1h: task.notified_1h || 'false',
      current_notified_15m: task.notified_15m || 'false'
    }
  });
}

return results;

const raw = $json.choices?.[0]?.message?.content || '';
const sessionData = $('Code Merge Session').first().json;
const userText = String(sessionData.text || '').trim();

let parsed;
try {
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
