  };
}

const normalize = (s) =>
  String(s || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '');

const extractRelativeDate = (text, nowStr) => {
  const t = String(text || '').trim();
  const now = new Date(`${nowStr}T00:00:00+07:00`);
  if (isNaN(now)) return '';

  const addDays = (d) => {
    const x = new Date(now);
    x.setDate(x.getDate() + d);
    const yyyy = x.getFullYear();
    const mm = String(x.getMonth() + 1).padStart(2, '0');
    const dd = String(x.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
  };

  if (t.includes('พรุ่งนี้')) return addDays(1);
  if (t.includes('มะรืน')) return addDays(2);
  if (t.includes('วันนี้')) return addDays(0);

  const mDate = t.match(/วันที่\s*(\d{1,2})/);
  if (mDate) {
    const day = Number(mDate[1]);
    let year = now.getFullYear();
    let month = now.getMonth();
    let candidate = new Date(year, month, day);
    if (candidate < now) candidate = new Date(year, month + 1, day);
    const yyyy = candidate.getFullYear();
    const mm = String(candidate.getMonth() + 1).padStart(2, '0');
    const dd = String(candidate.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
  }

  const weekdays = {
    'วันอาทิตย์': 0,
    'วันจันทร์': 1,
    'วันอังคาร': 2,
    'วันพุธ': 3,
    'วันพฤหัส': 4,
    'วันศุกร์': 5,
    'วันเสาร์': 6
  };

  for (const [k, v] of Object.entries(weekdays)) {
    if (t.includes(k)) {
      const cur = now.getDay();
      let delta = (v - cur + 7) % 7;
      if (delta === 0) delta = 7;
      return addDays(delta);
    }
  }

  return '';
};

const extractTime = (text) => {
  const t = String(text || '').trim().toLowerCase();

  if (/(^|\s)เที่ยงคืน($|\s)/.test(t)) return '00:00';
  if (/(^|\s)เที่ยง($|\s)/.test(t)) return '12:00';

  let m = t.match(/(\d{1,2})[:.](\d{2})/);
  if (m) {
    const hh = String(Number(m[1])).padStart(2, '0');
    const mm = String(Number(m[2])).padStart(2, '0');
    return `${hh}:${mm}`;
  }

  m = t.match(/ตี\s*(\d{1,2})(?:\s*โมง)?/);
  if (m) return `${String(Number(m[1])).padStart(2, '0')}:00`;

  m = t.match(/บ่าย\s*(\d{1,2})/);
  if (m) return `${String((Number(m[1]) % 12) + 12).padStart(2, '0')}:00`;

  m = t.match(/เย็น\s*(\d{1,2})/);
  if (m) return `${String((Number(m[1]) % 12) + 12).padStart(2, '0')}:00`;

  if (t.includes('ทุ่มครึ่ง')) return '19:30';

  m = t.match(/(\d{1,2})\s*โมง(?:\s*เช้า)?/);
  if (m) {
    let hour = Number(m[1]);
    if (t.includes('บ่าย') || t.includes('เย็น')) {
      hour = (hour % 12) + 12;
    }
    return `${String(hour).padStart(2, '0')}:00`;
  }

  return '';
};

const stripTemporalParts = (text) => {
  return String(text || '')
    .replace(/พรุ่งนี้/g, '')
    .replace(/มะรืน/g, '')
    .replace(/วันนี้/g, '')
    .replace(/วันอาทิตย์|วันจันทร์|วันอังคาร|วันพุธ|วันพฤหัส|วันศุกร์|วันเสาร์/g, '')
    .replace(/วันที่\s*\d{1,2}/g, '')
    .replace(/\d{1,2}[:.]\d{2}/g, '')
    .replace(/ตี\s*\d{1,2}(?:\s*โมง)?/g, '')
    .replace(/บ่าย\s*\d{1,2}/g, '')
    .replace(/เย็น\s*\d{1,2}/g, '')
    .replace(/\d{1,2}\s*โมง(?:\s*เช้า)?/g, '')
    .replace(/ทุ่มครึ่ง/g, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const inferTaskNameFromText = (text) => {
  let s = stripTemporalParts(text);

  s = s
    .replace(/^(คือ|ว่า|ประมาณ|สัก|ตอบ|เอา|ตอน|เวลา)\s*/g, '')
    .replace(/^ต้อง\s*/g, '')
    .replace(/^มี\s*/g, '')
    .replace(/^ไป\s*/g, 'ไป')
    .replace(/^แล้ว\s*/g, '')
    .replace(/^ก็\s*/g, '')
    .trim();

  s = s.replace(/^(แล้ว|ต่อ|กับ)\s*/g, '').trim();

  return s;
};

const extractFollowupSubject = (text, taskName) => {
